{
  "name": "Penjana Surat Pelepasan Sekolah Agama (SKSA)",
  "description": "Aplikasi web untuk menjana surat pelepasan murid SK Sungai Abong ke Sekolah Agama dengan format rasmi dan keupayaan muat turun PDF."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Student {
  id: string;
  name: string;
  class: string;
}

export interface LetterData {
  rujukan: string;
  tarikh: string;
  namaSekAgama: string;
  namaProgram: string;
  tarikhProgram: string;
  hariProgram: string;
  students: Student[];
  userEmail: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  GENERATING = 'GENERATING',
  SENDING = 'SENDING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import React, { useState, useRef, useEffect } from 'react';
import { LetterData, Student, AppStatus } from './types';
import { Plus, Trash2, FileText, Send, Download, CheckCircle2, AlertCircle, Loader2 } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [data, setData] = useState<LetterData>({
    rujukan: '',
    tarikh: new Date().toLocaleDateString('ms-MY'),
    namaSekAgama: '',
    namaProgram: '',
    tarikhProgram: '',
    hariProgram: '',
    students: [{ id: '1', name: '', class: '' }],
    userEmail: ''
  });

  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const letterRef = useRef<HTMLDivElement>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => {
      const newData = { ...prev, [name]: value };

      // Auto-calculate day if tarikhProgram changes
      if (name === 'tarikhProgram') {
        const date = new Date(value);
        if (!isNaN(date.getTime())) {
          const days = ['Ahad', 'Isnin', 'Selasa', 'Rabu', 'Khamis', 'Jumaat', 'Sabtu'];
          newData.hariProgram = days[date.getDay()];
        }
      }
      return newData;
    });
  };

  const addStudent = () => {
    setData(prev => ({
      ...prev,
      students: [...prev.students, { id: Date.now().toString(), name: '', class: '' }]
    }));
  };

  const removeStudent = (id: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.length > 1 ? prev.students.filter(s => s.id !== id) : prev.students
    }));
  };

  const updateStudent = (id: string, field: 'name' | 'class', value: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.map(s => s.id === id ? { ...s, [field]: value } : s)
    }));
  };

  const generatePDF = async () => {
    if (!letterRef.current) return;
    setStatus(AppStatus.GENERATING);

    try {
      const canvas = await html2canvas(letterRef.current, {
        scale: 2,
        useCORS: true,
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Surat_Pelepasan_${data.namaProgram.replace(/\s+/g, '_')}.pdf`);
      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
    } catch (error) {
      console.error(error);
      setStatus(AppStatus.ERROR);
    }
  };

  const handleSendEmail = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!data.userEmail) return;

    setStatus(AppStatus.SENDING);
    // Simulate API call to backend for email sending
    setTimeout(() => {
      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
      alert(`Berjaya! Surat telah dihantar ke emel: ${data.userEmail}. (Simulasi)`);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      <header className="max-w-6xl mx-auto mb-8 text-center md:text-left flex flex-col md:flex-row md:items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Penjana Surat Pelepasan</h1>
          <p className="text-slate-600">SK Sungai Abong (JBA 5095)</p>
        </div>
        <div className="mt-4 md:mt-0 flex gap-2 justify-center">
          <button 
            onClick={generatePDF}
            disabled={status !== AppStatus.IDLE}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg font-semibold transition disabled:opacity-50"
          >
            {status === AppStatus.GENERATING ? <Loader2 className="animate-spin" /> : <Download size={20} />}
            Muat Turun PDF
          </button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Input Form */}
        <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h2 className="text-xl font-bold mb-6 text-slate-800 flex items-center gap-2">
            <FileText className="text-blue-600" /> Maklumat Surat
          </h2>

          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">No. Rujukan</label>
                <input 
                  type="text" 
                  name="rujukan" 
                  value={data.rujukan}
                  onChange={handleInputChange}
                  placeholder="Contoh: 01/2024"
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Tarikh Surat</label>
                <input 
                  type="text" 
                  name="tarikh" 
                  value={data.tarikh}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nama Sekolah Agama</label>
              <input 
                type="text" 
                name="namaSekAgama" 
                value={data.namaSekAgama}
                onChange={handleInputChange}
                placeholder="Nama Sekolah Agama Tujuan"
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nama Program</label>
              <input 
                type="text" 
                name="namaProgram" 
                value={data.namaProgram}
                onChange={handleInputChange}
                placeholder="Contoh: Kejohanan Bola Sepak MSSD"
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Tarikh Program</label>
                <input 
                  type="date" 
                  name="tarikhProgram" 
                  value={data.tarikhProgram}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Hari</label>
                <input 
                  type="text" 
                  name="hariProgram" 
                  value={data.hariProgram}
                  readOnly
                  className="w-full px-4 py-2 border rounded-lg bg-slate-50 outline-none"
                />
              </div>
            </div>

            <hr className="my-6" />

            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-sm font-medium text-slate-700">Senarai Nama Murid</label>
                <button 
                  onClick={addStudent}
                  className="text-sm flex items-center gap-1 text-blue-600 hover:text-blue-700 font-semibold"
                >
                  <Plus size={16} /> Tambah Murid
                </button>
              </div>
              <div className="space-y-3 max-h-60 overflow-y-auto pr-2">
                {data.students.map((student, index) => (
                  <div key={student.id} className="flex gap-2 items-center">
                    <span className="text-slate-400 text-xs w-4">{index + 1}.</span>
                    <input 
                      type="text" 
                      placeholder="Nama Murid"
                      value={student.name}
                      onChange={(e) => updateStudent(student.id, 'name', e.target.value)}
                      className="flex-1 px-3 py-1.5 border rounded-lg text-sm"
                    />
                    <input 
                      type="text" 
                      placeholder="Kelas"
                      value={student.class}
                      onChange={(e) => updateStudent(student.id, 'class', e.target.value)}
                      className="w-20 px-3 py-1.5 border rounded-lg text-sm"
                    />
                    <button 
                      onClick={() => removeStudent(student.id)}
                      className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </div>
            </div>

            <hr className="my-6" />

            <form onSubmit={handleSendEmail} className="bg-blue-50 p-4 rounded-lg border border-blue-100">
              <label className="block text-sm font-medium text-blue-800 mb-2">Hantar ke Emel</label>
              <div className="flex gap-2">
                <input 
                  type="email" 
                  required
                  placeholder="alamat@emel.com"
                  value={data.userEmail}
                  onChange={(e) => setData({...data, userEmail: e.target.value})}
                  className="flex-1 px-4 py-2 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <button 
                  type="submit"
                  disabled={status !== AppStatus.IDLE}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 disabled:opacity-50 transition"
                >
                  {status === AppStatus.SENDING ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
                  Hantar
                </button>
              </div>
            </form>
          </div>
        </section>

        {/* Live Preview */}
        <section className="sticky top-8">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">Pratonton Surat</h2>
            {status === AppStatus.SUCCESS && (
              <span className="flex items-center gap-1 text-green-600 text-sm font-medium animate-pulse">
                <CheckCircle2 size={16} /> Selesai!
              </span>
            )}
            {status === AppStatus.ERROR && (
              <span className="flex items-center gap-1 text-red-600 text-sm font-medium">
                <AlertCircle size={16} /> Ralat berlaku
              </span>
            )}
          </div>

          <div className="bg-white shadow-2xl rounded-sm overflow-hidden border border-slate-300">
             {/* Printable Area */}
             <div 
              ref={letterRef}
              id="letter-content"
              className="p-12 text-[12pt] leading-relaxed bg-white text-black min-h-[1123px] w-full max-w-[794px] mx-auto overflow-hidden"
              style={{ fontFamily: 'Times New Roman, serif' }}
             >
                {/* Header */}
                <div className="flex items-center border-b-2 border-black pb-4 mb-6">
                  <div className="w-24 h-24 mr-6 flex items-center justify-center bg-slate-100 font-bold text-xs text-center border">
                    LOGO SKSA
                  </div>
                  <div className="flex-1 leading-tight">
                    <div className="text-xl font-bold">SEKOLAH KEBANGSAAN SUNGAI ABONG (JBA 5095)</div>
                    <div>Jln Sungai Abong <span className="float-right">Tel : 06 - 9549634</span></div>
                    <div>84000 Muar <span className="float-right">Kod Sekolah : JBA5095</span></div>
                    <div>Johor Darul Takzim <span className="float-right">E-mel : jba5095@moe.edu.my</span></div>
                  </div>
                </div>

                {/* Body Content */}
                <div className="flex justify-end mb-8">
                  <div className="text-right">
                    <div>Rujukan Kami : 600/3/1/{data.rujukan || '............'}</div>
                    <div>Tarikh : {data.tarikh || '............'}</div>
                  </div>
                </div>

                <div className="mb-6">
                  Guru Besar<br />
                  Sekolah Agama {data.namaSekAgama || '...........................................'},<br />
                  <br />
                  Tuan/Puan,<br />
                  <br />
                  <div className="font-bold uppercase underline">
                    MEMOHON KEBENARAN PELEPASAN MURID UNTUK {data.namaProgram || '...........................................'}
                  </div>
                </div>

                <div className="mb-4">
                  Dengan segala hormatnya perkara di atas adalah dirujuk.
                </div>

                <div className="mb-4">
                  2. Untuk makluman pihak tuan / puan, murid seperti dalam dalam lampiran terlibat dengan {data.namaProgram || '...........................................'}
                </div>

                <div className="ml-8 mb-6 grid grid-cols-[100px_auto]">
                  <div>Tarikh</div>: {data.tarikhProgram || '.....................'}
                  <div>Hari</div>: {data.hariProgram || '.....................'}
                </div>

                <div className="mb-4 text-justify">
                  3. Sehubungan dengan itu, pihak sekolah ingin memohon jasa baik pihak tuan / puan memberi pelepasan kepada murid terlibat.
                </div>

                <div className="mb-8 text-justify">
                  4. Kerjasama dan sokongan tuan / puan amat kami hargai. Dilampirkan bersama – sama surat ini senarai nama murid yang terlibat untuk makluman tuan / puan selanjutnya. Sebarang pertanyaan boleh menghubungi Pn Zuriana bt Kamarudin, GPK Kokurikulum di talian 069549634.
                </div>

                <div className="mb-12">
                  Sekian, terima kasih.<br /><br />
                  <span className="font-bold">“MALAYSIA MADANI”</span><br />
                  <span className="font-bold">“BERKHIDMAT UNTUK NEGARA”</span><br />
                  <br />
                  Saya yang menjalankan amanah,<br /><br /><br /><br />
                  ...........................................................<br />
                  <span className="font-bold">(SITI ZALEHA BINTI RAMLAN)</span><br />
                  Guru Besar,<br />
                  Sekolah Kebangsaan Sungai Abong.
                </div>

                {/* Attachment Page Simulation / Table */}
                <div className="mt-12 pt-8 border-t border-dashed border-slate-300">
                   <div className="font-bold underline mb-4 text-center">LAMPIRAN: SENARAI NAMA MURID</div>
                   <table className="w-full border-collapse border border-black text-sm">
                      <thead>
                        <tr className="bg-slate-50">
                          <th className="border border-black px-2 py-1 w-12">Bil</th>
                          <th className="border border-black px-2 py-1 text-left">Nama Murid</th>
                          <th className="border border-black px-2 py-1 w-24">Kelas</th>
                        </tr>
                      </thead>
                      <tbody>
                        {data.students.map((s, i) => (
                          <tr key={s.id}>
                            <td className="border border-black px-2 py-1 text-center">{i + 1}</td>
                            <td className="border border-black px-2 py-1 uppercase">{s.name || '........................................'}</td>
                            <td className="border border-black px-2 py-1 text-center">{s.class || '.........'}</td>
                          </tr>
                        ))}
                      </tbody>
                   </table>
                </div>
             </div>
          </div>
        </section>
      </main>

      <footer className="max-w-6xl mx-auto mt-12 py-8 border-t text-center text-slate-500 text-sm">
        &copy; {new Date().getFullYear()} SK Sungai Abong. Sistem Penjanaan Surat Rasmi.
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { LetterData, Student, AppStatus } from './types';
import { Plus, Trash2, FileText, Send, Download, CheckCircle2, AlertCircle, Loader2, RefreshCw } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [sequence, setSequence] = useState<number>(() => {
    const saved = localStorage.getItem('sksa_ref_sequence');
    return saved ? parseInt(saved, 10) : 1;
  });

  const getInitialDate = () => {
    const d = new Date();
    return d.toISOString().split('T')[0];
  };

  const [data, setData] = useState<LetterData>({
    rujukan: sequence.toString(),
    tarikh: getInitialDate(),
    namaSekAgama: '',
    namaProgram: '',
    tarikhProgram: '',
    hariProgram: '',
    students: [{ id: '1', name: '', class: '' }],
    userEmail: ''
  });

  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const letterRef = useRef<HTMLDivElement>(null);

  // Update rujukan whenever sequence changes
  useEffect(() => {
    setData(prev => ({ ...prev, rujukan: sequence.toString() }));
    localStorage.setItem('sksa_ref_sequence', sequence.toString());
  }, [sequence]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => {
      const newData = { ...prev, [name]: value };

      // Auto-calculate day if tarikhProgram changes
      if (name === 'tarikhProgram') {
        const date = new Date(value);
        if (!isNaN(date.getTime())) {
          const days = ['Ahad', 'Isnin', 'Selasa', 'Rabu', 'Khamis', 'Jumaat', 'Sabtu'];
          newData.hariProgram = days[date.getDay()];
        }
      }
      return newData;
    });
  };

  const formatDateMalay = (dateStr: string) => {
    if (!dateStr) return '............';
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return dateStr;
    const months = [
      'Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun',
      'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'
    ];
    return `${date.getDate()} ${months[date.getMonth()]} ${date.getFullYear()}`;
  };

  const addStudent = () => {
    setData(prev => ({
      ...prev,
      students: [...prev.students, { id: Date.now().toString(), name: '', class: '' }]
    }));
  };

  const removeStudent = (id: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.length > 1 ? prev.students.filter(s => s.id !== id) : prev.students
    }));
  };

  const updateStudent = (id: string, field: 'name' | 'class', value: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.map(s => s.id === id ? { ...s, [field]: value } : s)
    }));
  };

  const incrementSequence = () => {
    setSequence(prev => prev + 1);
  };

  const generatePDF = async () => {
    if (!letterRef.current) return;
    setStatus(AppStatus.GENERATING);

    try {
      const canvas = await html2canvas(letterRef.current, {
        scale: 2,
        useCORS: true,
        logging: false,
        allowTaint: true
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Surat_Pelepasan_${data.namaProgram.replace(/\s+/g, '_') || 'SKSA'}.pdf`);

      // Increment sequence after success
      incrementSequence();

      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
    } catch (error) {
      console.error(error);
      setStatus(AppStatus.ERROR);
    }
  };

  const handleSendEmail = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!data.userEmail) return;

    setStatus(AppStatus.SENDING);
    // Simulate API call
    setTimeout(() => {
      incrementSequence();
      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
      alert(`Berjaya! Surat telah dihantar ke emel: ${data.userEmail}. Nombor rujukan telah dikemaskini.`);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      <header className="max-w-6xl mx-auto mb-8 text-center md:text-left flex flex-col md:flex-row md:items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Penjana Surat Pelepasan</h1>
          <p className="text-slate-600">SK Sungai Abong (JBA 5095) - Automatik & Rasmi</p>
        </div>
        <div className="mt-4 md:mt-0 flex gap-2 justify-center">
          <button 
            onClick={generatePDF}
            disabled={status !== AppStatus.IDLE}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg font-semibold transition disabled:opacity-50 shadow-lg shadow-blue-200"
          >
            {status === AppStatus.GENERATING ? <Loader2 className="animate-spin" /> : <Download size={20} />}
            Muat Turun PDF
          </button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Input Form */}
        <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
          <h2 className="text-xl font-bold mb-6 text-slate-800 flex items-center gap-2">
            <FileText className="text-blue-600" /> Maklumat Surat
          </h2>

          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center justify-between">
                  No. Rujukan 
                  <button 
                    onClick={() => setSequence(1)} 
                    className="text-[10px] text-slate-400 hover:text-red-500 flex items-center gap-1"
                    title="Reset No. Rujukan"
                  >
                    <RefreshCw size={10} /> Reset
                  </button>
                </label>
                <input 
                  type="text" 
                  name="rujukan" 
                  value={data.rujukan}
                  onChange={handleInputChange}
                  placeholder="Contoh: 1"
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 font-mono"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Tarikh Surat</label>
                <input 
                  type="date" 
                  name="tarikh" 
                  value={data.tarikh}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nama Sekolah Agama</label>
              <input 
                type="text" 
                name="namaSekAgama" 
                value={data.namaSekAgama}
                onChange={handleInputChange}
                placeholder="contoh:Sekolah Agama Pangiran Affendy"
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nama Program</label>
              <input 
                type="text" 
                name="namaProgram" 
                value={data.namaProgram}
                onChange={handleInputChange}
                placeholder="Contoh: Kejohanan Bola Sepak MSSD"
