        </div>
        <div className="flex flex-col sm:flex-row gap-3 justify-center">
          <a 
            href={DRIVE_LINK} 
            target="_blank" 
            rel="noopener noreferrer"
            className="flex items-center justify-center gap-2 text-slate-700 hover:text-blue-600 font-semibold transition bg-white px-5 py-2.5 rounded-xl border border-slate-200 shadow-sm"
          >
            <ExternalLink size={18} /> Folder Google Drive
          </a>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        {/* Input Form */}
        <section className="lg:col-span-5 bg-white p-6 md:p-8 rounded-2xl shadow-xl border border-slate-200 h-fit">
          <h2 className="text-xl font-bold mb-8 text-slate-800 flex items-center gap-2 border-b pb-4">
            <FileText className="text-blue-600" /> Butiran Surat Rasmi
          </h2>

          <div className="space-y-6">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2 flex items-center justify-between">
                  No. Rujukan 
                  <button onClick={() => setSequence(1)} className="text-[10px] bg-slate-100 px-2 py-1 rounded text-slate-500 hover:text-red-500 flex items-center gap-1 transition">
                    <RefreshCw size={10} /> Reset
                  </button>
                </label>
                <input type="text" name="rujukan" value={data.rujukan} onChange={handleInputChange} className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none bg-slate-50 font-mono text-blue-700 font-bold" />
              </div>
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">Tarikh Surat</label>
                <input type="date" name="tarikh" value={data.tarikh} onChange={handleInputChange} className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Nama Sekolah Agama (Penerima)</label>
              <input type="text" name="namaSekAgama" value={data.namaSekAgama} onChange={handleInputChange} placeholder="Contoh: Sekolah Agama Parit Bakar" className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Nama Program / Aktiviti</label>
              <input type="text" name="namaProgram" value={data.namaProgram} onChange={handleInputChange} placeholder="Contoh: Kejohanan Bola Jaring MSSD" className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none" />
            </div>

