                    <input type="text" placeholder="Kelas" value={student.class} onChange={(e) => updateStudent(student.id, 'class', e.target.value)} className="w-20 px-3 py-2 border border-slate-200 rounded-lg text-sm outline-none focus:border-blue-400 text-center" />
