        allowTaint: true,
        backgroundColor: "#ffffff",
        // Paksa lebar A4 semasa capture supaya tak terpotong kalau skrin mobile
        width: 794,
        windowWidth: 794,
        onclone: (clonedDoc) => {
          const clonedElement = clonedDoc.getElementById('letter-content');
