                   <input type="text" name="rujukan" value={data.rujukan} onChange={handleInputChange} className="w-full px-3 py-2 border-2 border-slate-100 rounded-lg focus:border-blue-500 outline-none bg-slate-50 font-mono text-blue-700 font-bold" />
                   <button onClick={() => setSequence(1)} className="p-2 bg-slate-100 rounded-lg text-slate-400 hover:text-red-500 transition"><RefreshCw size={14} /></button>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">Tarikh Surat</label>
                <input type="date" name="tarikh" value={data.tarikh} onChange={handleInputChange} className="w-full px-3 py-2 border-2 border-slate-100 rounded-lg focus:border-blue-500 outline-none" />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">Nama Sekolah Agama</label>
              <input type="text" name="namaSekAgama" value={data.namaSekAgama} onChange={handleInputChange} placeholder="Sekolah Agama..." className="w-full px-4 py-2.5 border-2 border-slate-100 rounded-lg focus:border-blue-500 outline-none" />
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">Nama Program</label>
              <input type="text" name="namaProgram" value={data.namaProgram} onChange={handleInputChange} placeholder="Kejohanan..." className="w-full px-4 py-2.5 border-2 border-slate-100 rounded-lg focus:border-blue-500 outline-none" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black text-slate-500 mb-1 uppercase tracking-wider">Tarikh Program</label>
                <input type="date" name="tarikhProgram" value={data.tarikhProgram} onChange={handleInputChange} className="w-full px-3 py-2 border-2 border-slate-100 rounded-lg focus:border-blue-500 outline-none" />
              </div>
