              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Tarikh Program</label>
                <input type="date" name="tarikhProgram" value={data.tarikhProgram} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Hari</label>
                <input type="text" name="hariProgram" value={data.hariProgram} readOnly className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl bg-slate-200/50 outline-none font-black text-slate-500 text-xs" />
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <div className="flex items-center justify-between mb-4">
