      const fileName = `Surat_Pelepasan_SKSA_${data.namaProgram.replace(/\s+/g, '_') || 'Rasmi'}.pdf`;

      // 1. Simpan secara lokal dulu (Download)
      pdf.save(fileName);

      // 2. Upload ke Google Drive & Emel via Apps Script
      setStatus(AppStatus.UPLOADING);
      const pdfBase64 = pdf.output('datauristring').split(',')[1];

      const response = await fetch(APPS_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', // Kerana Apps Script redirection, guna no-cors atau pastikan handle response dengan betul
        body: JSON.stringify({
          pdfBase64: pdfBase64,
          fileName: fileName,
          email: data.email,
          program: data.namaProgram || "Program Sekolah"
        })
      });

      // Nota: 'no-cors' tidak akan membenarkan kita baca JSON response, tapi data tetap sampai.
      // Jika mahu response, Apps Script perlu setup CORS header (lebih teknikal).

      setSequence(prev => prev + 1);
      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
    } catch (error) {
      console.error("PDF Export/Upload Error:", error);
      setStatus(AppStatus.ERROR);
    }
  };

  return (
    <div className="min-h-screen bg-slate-100 p-2 md:p-6">
      <header className="max-w-6xl mx-auto mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 border-b-2 border-slate-200 pb-5">
