          <img src={LOGO_SKSA} alt="Logo SKSA" className="w-16 h-16 object-contain rounded-xl shadow-md border-2 border-white" crossOrigin="anonymous" />
          <div className="text-left">
            <h1 className="text-xl md:text-2xl font-black text-slate-900 leading-none tracking-tight">SISTEM PENJANA SURAT</h1>
            <p className="text-blue-700 font-black uppercase text-sm md:text-lg tracking-tighter mt-1">SK SG ABONG, MUAR</p>
          </div>
        </div>
        <div className="flex justify-center">
          <a href={DRIVE_LINK} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 text-slate-600 hover:text-blue-600 font-bold transition bg-white px-5 py-2.5 rounded-xl border border-slate-200 shadow-sm text-xs uppercase tracking-widest text-center">
            <ExternalLink size={14} /> Lihat Rekod Drive
          </a>
        </div>
      </header>

      <main className="max-w-7xl mx-auto grid grid-cols-1 xl:grid-cols-12 gap-6 items-start">
        {/* INPUT FORM */}
        <section className="xl:col-span-4 bg-white p-6 rounded-3xl shadow-xl border border-slate-200">
          <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
             <div className="w-2.5 h-2.5 bg-blue-600 rounded-full animate-pulse"></div> Pengisian Digital
          </h2>

          <div className="space-y-5">
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">No. Rujukan</label>
                <div className="flex gap-1">
                   <input type="text" name="rujukan" value={data.rujukan} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 font-mono text-blue-700 font-bold text-xs" />
                   <button onClick={() => setSequence(1)} className="p-2.5 bg-slate-50 rounded-xl text-slate-300 hover:text-red-500 transition"><RefreshCw size={14} /></button>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Tarikh Surat</label>
                <input type="date" name="tarikh" value={data.tarikh} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
              </div>
