import React, { useState, useRef, useEffect } from 'react';
import { LetterData, Student, AppStatus } from './types';
import { Plus, Trash2, FileText, Download, CheckCircle2, AlertCircle, Loader2, RefreshCw, ExternalLink, CloudUpload, Mail } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

// URL APPS SCRIPT YANG TUAN BERIKAN
const APPS_SCRIPT_URL = "https://script.google.com/macros/s/AKfycbwvX2haBQivIVgYEHdpqx-nMM8-hPZQLmCWANM9gCjFNbZuApdekiKyA7wxGl3bclWw/exec"; 

const App: React.FC = () => {
  const [sequence, setSequence] = useState<number>(() => {
    const saved = localStorage.getItem('sksa_ref_sequence');
    return saved ? parseInt(saved, 10) : 1;
  });

  const getInitialDate = () => {
    const d = new Date();
    return d.toISOString().split('T')[0];
  };

  const [data, setData] = useState<LetterData>({
    rujukan: sequence.toString(),
    tarikh: getInitialDate(),
    namaSekAgama: '',
    namaProgram: '',
    tarikhProgram: '',
    hariProgram: '',
    email: '',
    students: [{ id: '1', name: '', class: '' }]
  });

  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const page1Ref = useRef<HTMLDivElement>(null);
  const page2Ref = useRef<HTMLDivElement>(null);

  const DRIVE_LINK = "https://drive.google.com/drive/folders/1F93DQWvLux858nB2kM8lSxKtJTNvdIgy?usp=drive_link";
  const LOGO_SKSA = "https://i.postimg.cc/rmdkLmLv/logo-sksa-1.jpg";

  useEffect(() => {
    setData(prev => ({ ...prev, rujukan: sequence.toString() }));
    localStorage.setItem('sksa_ref_sequence', sequence.toString());
  }, [sequence]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setData(prev => {
      const newData = { ...prev, [name]: value };
      if (name === 'tarikhProgram') {
        const date = new Date(value);
        if (!isNaN(date.getTime())) {
          const days = ['Ahad', 'Isnin', 'Selasa', 'Rabu', 'Khamis', 'Jumaat', 'Sabtu'];
          newData.hariProgram = days[date.getDay()];
        }
      }
      return newData;
    });
  };

  const formatDateMalay = (dateStr: string) => {
    if (!dateStr) return '............';
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return dateStr;
    const months = ['Januari', 'Februari', 'Mac', 'April', 'Mei', 'Jun', 'Julai', 'Ogos', 'September', 'Oktober', 'November', 'Disember'];
    return `${date.getDate()} ${months[date.getMonth()]} ${date.getFullYear()}`;
  };

  const addStudent = () => {
    setData(prev => ({
      ...prev,
      students: [...prev.students, { id: Date.now().toString(), name: '', class: '' }]
    }));
  };

  const removeStudent = (id: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.length > 1 ? prev.students.filter(s => s.id !== id) : prev.students
    }));
  };

  const updateStudent = (id: string, field: 'name' | 'class', value: string) => {
    setData(prev => ({
      ...prev,
      students: prev.students.map(s => s.id === id ? { ...s, [field]: value } : s)
    }));
  };

  const capturePage = async (ref: React.RefObject<HTMLDivElement>) => {
    if (!ref.current) return null;
    return await html2canvas(ref.current, {
      scale: 3,
      useCORS: true,
      allowTaint: true,
      backgroundColor: "#ffffff",
      scrollX: 0,
      scrollY: 0,
      width: 800,
      height: 1123,
    });
  };

  const generatePDF = async () => {
    if (!page1Ref.current || !page2Ref.current) return;
    setStatus(AppStatus.GENERATING);

    try {
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
      });

      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      const canvas1 = await capturePage(page1Ref);
      if (canvas1) {
        const imgData1 = canvas1.toDataURL('image/png');
        pdf.addImage(imgData1, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      pdf.addPage();
      const canvas2 = await capturePage(page2Ref);
      if (canvas2) {
        const imgData2 = canvas2.toDataURL('image/png');
        pdf.addImage(imgData2, 'PNG', 0, 0, pdfWidth, pdfHeight);
      }

      const fileName = `Surat_Pelepasan_SKSA_${data.namaProgram.replace(/\s+/g, '_') || 'Rasmi'}.pdf`;

      // 1. Simpan secara lokal dulu (Download)
      pdf.save(fileName);

      // 2. Upload ke Google Drive & Emel via Apps Script
      setStatus(AppStatus.UPLOADING);
      const pdfBase64 = pdf.output('datauristring').split(',')[1];

      // Menggunakan fetch ke Apps Script
      await fetch(APPS_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          pdfBase64: pdfBase64,
          fileName: fileName,
          email: data.email,
          program: data.namaProgram || "Program Sekolah"
        })
      });

      setSequence(prev => prev + 1);
      setStatus(AppStatus.SUCCESS);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
    } catch (error) {
      console.error("PDF Export/Upload Error:", error);
      setStatus(AppStatus.ERROR);
      alert("Maaf, terdapat ralat semasa menghantar fail. Sila pastikan Apps Script anda telah di-deploy dengan betul.");
    }
  };

