             <div className="w-2.5 h-2.5 bg-blue-600 rounded-full animate-pulse"></div> Borang Maklumat
          </h2>

          <div className="space-y-5">
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">No. Rujukan</label>
                <div className="flex gap-1">
                   <input type="text" name="rujukan" value={data.rujukan} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 font-mono text-blue-700 font-bold text-xs" />
                   <button onClick={() => setSequence(1)} title="Reset Sequence" className="p-2.5 bg-slate-50 rounded-xl text-slate-300 hover:text-red-500 transition border border-transparent hover:border-red-100"><RefreshCw size={14} /></button>
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Tarikh Surat</label>
                <input type="date" name="tarikh" value={data.tarikh} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Nama Sekolah Agama Penerima</label>
              <input type="text" name="namaSekAgama" value={data.namaSekAgama} onChange={handleInputChange} placeholder="Parit Kadhi/Sri Jong/Parit Setongkat" className="w-full px-4 py-3 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Nama Program / Acara</label>
              <input type="text" name="namaProgram" value={data.namaProgram} onChange={handleInputChange} placeholder="E.g. Kejohanan Olahraga MSSD Muar" className="w-full px-4 py-3 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Tarikh Program</label>
                <input type="date" name="tarikhProgram" value={data.tarikhProgram} onChange={handleInputChange} className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl focus:border-blue-500 outline-none bg-slate-50 text-xs font-bold" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-wider">Hari</label>
                <input type="text" name="hariProgram" value={data.hariProgram} readOnly className="w-full px-3 py-2.5 border-2 border-slate-50 rounded-xl bg-slate-200/50 outline-none font-black text-slate-500 text-xs" />
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <div className="flex items-center justify-between mb-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Senarai Murid Terlibat</label>
                <button onClick={addStudent} className="text-[10px] bg-slate-900 text-white px-4 py-2 rounded-full hover:bg-blue-600 font-bold transition flex items-center gap-2 shadow-lg active:scale-95">
                  <Plus size={12} /> Tambah Murid
                </button>
              </div>
              <div className="space-y-2 max-h-[250px] overflow-y-auto pr-1 custom-scrollbar">
                {data.students.map((student, index) => (
                  <div key={student.id} className="flex gap-2 items-center bg-slate-50/50 p-2 rounded-xl border border-slate-100 group hover:border-blue-100 transition">
                    <span className="text-slate-300 font-black text-[10px] w-5 text-center">{index + 1}</span>
                    <input type="text" placeholder="NAMA PENUH" value={student.name} onChange={(e) => updateStudent(student.id, 'name', e.target.value)} className="flex-1 px-3 py-2 bg-white border border-slate-200 rounded-lg text-[10px] uppercase font-bold outline-none focus:border-blue-400" />
                    <input type="text" placeholder="KELAS" value={student.class} onChange={(e) => updateStudent(student.id, 'class', e.target.value)} className="w-28 px-3 py-2 bg-white border border-slate-200 rounded-lg text-[10px] text-center font-bold outline-none focus:border-blue-400" />
                    <button onClick={() => removeStudent(student.id)} className="p-1.5 text-slate-300 hover:text-red-500 transition"><Trash2 size={16} /></button>
                  </div>
                ))}
              </div>
            </div>

            <div className="pt-2">
                <button 
                    onClick={generatePDF}
